BeatSkill = class("BeatSkill", BaseSkill)

function BeatSkill:onSkillStart(ticks)
    self:doDamage()
    self.skillStage = Define.SkillStage.SkillEnd
end

function BeatSkill:doDamage()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if player == nil then
        return
    end

    local entityId = player:getFirstChildrenEntityId()
    local hurter = PlayerManager:getPlayerByEntityId(entityId)

    --范围伤害
    if player:isAdvancing() then

    else
        local players = PlayerManager:getPlayers()
        for _, v in pairs(players) do
            if v and v.userId ~= player.userId and v:isBeGrab() == false
                    and MathUtil:distanceSquare2d(v:getPosition(), player:getPosition())
                    < math.pow(GameConfig.enemyRadius + player.radius * ClientConfig.adjustCoe, 2) then
                v:bePlayerAttacked(player, Define.HurtType.Attack, false, self.skillId)
            end
        end

        local actors = ActorManager:getActors()
        for _, actor in pairs(actors) do
            if MathUtil:distanceSquare2d(actor:getPosition(), player:getPosition())
                    < math.pow(GameConfig.enemyRadius + player.radius * ClientConfig.adjustCoe, 2) then
                actor:onActorHurt(player.property:getAttack(self.skillId))
            end
        end
    end

    --解绑
    player:unbindAllEntity()

    --对抓取者造成伤害
    if hurter then
        hurter:bePlayerAttacked(player, Define.HurtType.Skill, true, self.skillId)
    else
        local actor = ActorManager:getActor(entityId)
        if actor then
            actor:onActorHurt(player.property:getSkillAttack(self.skillId))
        end
    end
end

return BeatSkill